import type { Result } from './sw-controls.js';

export interface CacheInfo {
    name: string;
    entries: number;
}

export async function listCaches(): Promise<Result<{ caches: CacheInfo[] }>> {
    if (typeof caches === 'undefined') {
        return { ok: false, error: 'Cache API not available in this context' };
    }
    try {
        const names = await caches.keys();
        const info = await Promise.all(names.map(async (name): Promise<CacheInfo> => {
            const cache = await caches.open(name);
            const keys = await cache.keys();
            return { name, entries: keys.length };
        }));
        return { ok: true, caches: info };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function clearAllCaches(): Promise<Result<{ cleared: string[] }>> {
    if (typeof caches === 'undefined') {
        return { ok: false, error: 'Cache API not available in this context' };
    }
    try {
        const names = await caches.keys();
        await Promise.all(names.map((n) => caches.delete(n)));
        return { ok: true, cleared: names };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function listDatabases(): Promise<Result<{ databases: string[] }>> {
    try {
        const idb = indexedDB as unknown as { databases?: () => Promise<Array<{ name?: string }>> };
        if (typeof idb.databases !== 'function') {
            return { ok: false, error: 'indexedDB.databases() not supported by this browser' };
        }
        const list = await idb.databases();
        const names = list.map((d) => d.name).filter((n): n is string => typeof n === 'string');
        return { ok: true, databases: names };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function deleteAllDatabases(): Promise<Result<{ deleted: string[] }>> {
    const listed = await listDatabases();
    if (!listed.ok) return listed;

    try {
        await Promise.all(listed.databases.map((name) => deleteDatabase(name)));
        return { ok: true, deleted: listed.databases };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

function deleteDatabase(name: string): Promise<void> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.deleteDatabase(name);
        req.onsuccess = () => resolve();
        req.onerror = () => reject(new Error(`Failed to delete IndexedDB "${name}"`));
        req.onblocked = () => resolve();
    });
}

export function listSessionStorage(): Result<{ keys: string[]; bytes: number }> {
    try {
        const keys: string[] = [];
        let bytes = 0;
        for (let i = 0; i < sessionStorage.length; i++) {
            const key = sessionStorage.key(i);
            if (key === null) continue;
            keys.push(key);
            // Approximate UTF-16 byte cost: key + value, 2 bytes per char.
            const value = sessionStorage.getItem(key) ?? '';
            bytes += (key.length + value.length) * 2;
        }
        return { ok: true, keys, bytes };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export function clearSessionStorage(): Result<{ cleared: number }> {
    try {
        const cleared = sessionStorage.length;
        sessionStorage.clear();
        return { ok: true, cleared };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function nukeAndReload(): Promise<void> {
    const { unregisterSw } = await import('./sw-controls.js');
    await unregisterSw();
    await clearAllCaches();
    await deleteAllDatabases();
    clearSessionStorage();
    location.reload();
}

function formatError(err: unknown): string {
    if (err instanceof Error) return err.stack ?? err.message;
    return String(err);
}
