import {
    getSwStatus, unregisterSw, updateSw, skipWaiting,
} from '../../../../services/debug/sw-controls.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Service Worker</summary>
    <pre class="debug-code" data-role="status">Loading…</pre>
    <pre class="debug-code" data-role="output"></pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="sw-refresh">Refresh status</button>
        <button class="debug-btn" type="button" data-testid="sw-update">Update</button>
        <button class="debug-btn" type="button" data-testid="sw-skip-waiting">Skip waiting</button>
        <button class="debug-btn" type="button" data-testid="sw-unregister">Unregister</button>
    </div>
</details>
`;

export class DebugSwPanel extends HTMLElement {
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const statusEl = this.querySelector<HTMLPreElement>('[data-role="status"]')!;
        const outputEl = this.querySelector<HTMLPreElement>('[data-role="output"]')!;

        const renderStatus = async () => {
            statusEl.textContent = JSON.stringify(await getSwStatus(), null, 2);
        };

        this.querySelector<HTMLButtonElement>('[data-testid="sw-refresh"]')!
            .addEventListener('click', () => { void renderStatus(); });

        this.querySelector<HTMLButtonElement>('[data-testid="sw-update"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = JSON.stringify(await updateSw(), null, 2);
                await renderStatus();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="sw-skip-waiting"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = JSON.stringify(await skipWaiting(), null, 2);
                await renderStatus();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="sw-unregister"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Unregister the service worker?')) return;
                outputEl.textContent = JSON.stringify(await unregisterSw(), null, 2);
                await renderStatus();
            })(); });

        void renderStatus();
    }
}

if (!customElements.get('debug-sw-panel')) {
    customElements.define('debug-sw-panel', DebugSwPanel);
}
