import { API_URL } from '../../../../config.js';
import {
    snapshotConnectivity, pingBackend, type PingResult,
} from '../../../../services/debug/connectivity.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Connectivity</summary>
    <pre class="debug-code" data-role="status"></pre>
    <pre class="debug-code" data-role="ping">No ping yet.</pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="connectivity-ping">Ping backend</button>
    </div>
</details>
`;

function pingUrl(): string {
    return `${API_URL}/health`;
}

function formatPingResult(url: string, r: PingResult): string {
    return JSON.stringify({ url, ...r }, null, 2);
}

export class DebugConnectivityPanel extends HTMLElement {
    private initialized = false;
    private pollTimer: ReturnType<typeof setInterval> | null = null;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const statusEl = this.querySelector<HTMLPreElement>('[data-role="status"]')!;
        const pingResultEl = this.querySelector<HTMLPreElement>('[data-role="ping"]')!;
        const pingBtn = this.querySelector<HTMLButtonElement>('[data-testid="connectivity-ping"]')!;

        pingBtn.addEventListener('click', () => { void (async () => {
            pingResultEl.textContent = `Pinging ${pingUrl()}…`;
            const result = await pingBackend(pingUrl());
            pingResultEl.textContent = formatPingResult(pingUrl(), result);
        })(); });

        const render = () => {
            statusEl.textContent = JSON.stringify(snapshotConnectivity(), null, 2);
        };
        render();
        this.pollTimer = setInterval(render, 2000);
    }

    disconnectedCallback(): void {
        if (this.pollTimer) {
            clearInterval(this.pollTimer);
            this.pollTimer = null;
        }
    }
}

if (!customElements.get('debug-connectivity-panel')) {
    customElements.define('debug-connectivity-panel', DebugConnectivityPanel);
}
