import {
    listCaches, listDatabases, listSessionStorage,
    clearAllCaches, deleteAllDatabases, clearSessionStorage, nukeAndReload,
} from '../../../../services/debug/storage-controls.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Storage</summary>
    <pre class="debug-code" data-role="caches">Loading caches…</pre>
    <pre class="debug-code" data-role="dbs">Loading IndexedDB…</pre>
    <pre class="debug-code" data-role="session">Loading sessionStorage…</pre>
    <pre class="debug-code" data-role="output"></pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="storage-refresh">Refresh</button>
        <button class="debug-btn" type="button" data-testid="storage-clear-caches">Clear caches</button>
        <button class="debug-btn" type="button" data-testid="storage-delete-idb">Delete IDB</button>
        <button class="debug-btn" type="button" data-testid="storage-clear-session">Clear sessionStorage</button>
        <button class="debug-btn" type="button" data-testid="storage-nuke">Nuke &amp; reload</button>
    </div>
</details>
`;

export class DebugStoragePanel extends HTMLElement {
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const cachesEl = this.querySelector<HTMLPreElement>('[data-role="caches"]')!;
        const dbsEl = this.querySelector<HTMLPreElement>('[data-role="dbs"]')!;
        const sessionEl = this.querySelector<HTMLPreElement>('[data-role="session"]')!;
        const outputEl = this.querySelector<HTMLPreElement>('[data-role="output"]')!;

        const refresh = async () => {
            cachesEl.textContent = JSON.stringify(await listCaches(), null, 2);
            dbsEl.textContent = JSON.stringify(await listDatabases(), null, 2);
            sessionEl.textContent = JSON.stringify(listSessionStorage(), null, 2);
        };

        this.querySelector<HTMLButtonElement>('[data-testid="storage-refresh"]')!
            .addEventListener('click', () => { void refresh(); });

        this.querySelector<HTMLButtonElement>('[data-testid="storage-clear-caches"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Delete all Cache Storage entries?')) return;
                outputEl.textContent = JSON.stringify(await clearAllCaches(), null, 2);
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="storage-delete-idb"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Delete all IndexedDB databases?')) return;
                outputEl.textContent = JSON.stringify(await deleteAllDatabases(), null, 2);
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="storage-clear-session"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Clear all sessionStorage entries?')) return;
                outputEl.textContent = JSON.stringify(clearSessionStorage(), null, 2);
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="storage-nuke"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Unregister SW, clear all caches and IDB, then reload?')) return;
                await nukeAndReload();
            })(); });

        void refresh();
    }
}

if (!customElements.get('debug-storage-panel')) {
    customElements.define('debug-storage-panel', DebugStoragePanel);
}
