import {
    queryRecentClientLogs,
    flushClientLogBatch,
    pushClientLogEntry,
} from '../../../../services/debug/client-log-buffer.js';
import {
    deleteAllClientLogs,
    getRecentClientLogs,
} from '../../../../services/debug/client-log-store.js';
import { checkClientLogShippingAvailability } from '../../../../services/debug/client-log-shipping.js';
import '../../../log-viewer/log-viewer.component.js';
import type { LogViewer } from '../../../log-viewer/log-viewer.component.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Client Logs</summary>
    <div class="debug-shipping-status" data-testid="logs-shipping-status"></div>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="logs-refresh">Refresh</button>
        <button class="debug-btn" type="button" data-testid="logs-download">Download .txt</button>
        <button class="debug-btn" type="button" data-testid="logs-clear">Clear buffer</button>
    </div>
    <log-viewer></log-viewer>
</details>
`;

export class DebugLogsPanel extends HTMLElement {
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const statusEl = this.querySelector<HTMLElement>('[data-testid="logs-shipping-status"]')!;
        const refreshBtn = this.querySelector<HTMLButtonElement>('[data-testid="logs-refresh"]')!;
        const downloadBtn = this.querySelector<HTMLButtonElement>('[data-testid="logs-download"]')!;
        const clearBtn = this.querySelector<HTMLButtonElement>('[data-testid="logs-clear"]')!;
        const viewer = this.querySelector('log-viewer') as LogViewer;

        viewer.availableLevels = ['debug', 'info', 'warn', 'error'];
        viewer.source = async (filters) => queryRecentClientLogs(filters);

        const refreshShipping = async () => {
            const status = await checkClientLogShippingAvailability();
            statusEl.textContent = status.ok
                ? 'Shipping: ok (Background Sync API registered)'
                : `Shipping: BROKEN — ${status.error}`;
            statusEl.classList.toggle('ok', status.ok);
            statusEl.classList.toggle('broken', !status.ok);
        };

        refreshBtn.addEventListener('click', () => { void (async () => {
            await refreshShipping();
            viewer.refresh();
        })(); });

        downloadBtn.addEventListener('click', () => { void this.downloadLogs(); });

        clearBtn.addEventListener('click', () => { void (async () => {
            await deleteAllClientLogs();
            // Visible marker so the clear is obvious even when polling
            // keeps feeding the store seconds later.
            pushClientLogEntry({ level: 'info', module: 'debug', message: '— buffer cleared —' });
            await flushClientLogBatch();
            viewer.refresh();
        })(); });

        void refreshShipping();
    }

    private async downloadLogs(): Promise<void> {
        await flushClientLogBatch();
        const response = await getRecentClientLogs(10_000);
        const text = response.entries.map((e) => JSON.stringify(e)).join('\n') + '\n';
        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `motivation-client-logs-${Temporal.Now.instant().toString()}.txt`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 1000);
    }
}

if (!customElements.get('debug-logs-panel')) {
    customElements.define('debug-logs-panel', DebugLogsPanel);
}
